#include <bits/stdc++.h>
using namespace std;
unsigned long long n;
unsigned long long pow1(unsigned long long a,unsigned long long b){
	unsigned long long ann=1;
	for(int i=0;i<b;i++){
		ann*=a;
	}
	return ann;
}
int main() {
	cin>>n;
	if(n%2==1) {
		cout<<-1<<endl;
		return 0;
	}
	while(n>0) {
		unsigned long long i=1;
		while(pow1(2,i)<=n) {
			i++;
		}
		cout<<pow1(2,i-1)<<" ";
		n-=pow1(2,i-1);
	}
	return 0;
}
